    '00000000-0000-0003-0001-000000000003',
    'colleague-skill-gap-003',
    'Skill Gap Coaching: Development Support',
    'colleague_facing',
    'Training & Development',
    'intermediate',
    12,
    'Practice coaching conversations about skill gaps while maintaining colleague dignity, supporting ownership of development, and using a facilitative approach',
    'A colleague has identified skill gaps or has had skill gaps identified through performance processes. They may feel defensive, ashamed, or uncertain. Your role is to use a facilitative coaching approach - helping them explore their development goals, recognize their strengths, and identify their own learning path while maintaining their dignity and autonomy. This applies core MI skills to internal workplace development.',
    '{"name": "Sam", "role": "colleague", "background": "Has been in their role for 18 months. Recently received feedback about skill gaps in some areas. Feeling defensive but also aware that development is needed. Some anxiety about capability and future prospects. Mixed between wanting to improve and feeling inadequate.", "personality_traits": ["defensive", "aware", "growth_minded", "anxious"], "tone_spectrum": {"word_complexity": 0.5, "sentence_length": 0.5, "emotional_expressiveness": 0.5, "disclosure_level": 0.4, "response_latency": 0.5, "confidence_level": 0.4}, "starting_tone_position": 0.3, "triggers": ["judgment", "comparison_to_others", "criticism_without_balance", "being_told_what_to_learn"], "comfort_topics": ["strengths_recognition", "autonomy_in_learning", "support", "balanced_perspective"]}'::jsonb,
    '{"start_node_id": "node_1", "nodes": {"node_1": {"id": "node_1", "persona_text": "I got some feedback recently about areas where I need to develop. Honestly, it stings a bit, but I know there are some skills I need to work on. I''m just not sure where to start.", "persona_mood": "defensive_open", "themes": ["Defensiveness", "Awareness", "Uncertainty"], "choice_points": [{"id": "cp_node_1_0", "option_text": "Yes, I''ve noticed those gaps too. You really need to focus on X and Y skills - they''re essential.", "preview_hint": "This confirms the criticism and directs", "rapport_impact": -1, "trust_impact": -1, "tone_shift": -0.15, "technique_tags": ["confirming_deficit"], "competency_links": [], "feedback": {"immediate": "You''ve confirmed the deficit and directed learning rather than exploring their perspective. This increases defensiveness.", "learning_note": "Skill gap conversations require balancing strengths with development needs."}, "next_node_id": "node_2a", "exploration_depth": "surface"}, {"id": "cp_node_1_1", "option_text": "You''re feeling stung by the feedback, but you also recognize there are areas where you need to develop.", "preview_hint": "This reflects both feelings and awareness", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["double_sided_reflection"], "competency_links": ["A6", "A4"], "feedback": {"immediate": "Excellent double-sided reflection! You''ve captured both the emotional sting and the self-awareness.", "learning_note": "Double-sided reflections honor both feelings and awareness in development conversations."}, "next_node_id": "node_2b", "exploration_depth": "deep"}, {"id": "cp_node_1_2", "option_text": "What development areas stood out to you from the feedback?", "preview_hint": "This invites their perspective", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.1, "technique_tags": ["open_question"], "competency_links": ["A6"], "feedback": {"immediate": "Perfect open question! This invites them to share their perspective on the feedback.", "learning_note": "Open questions help colleagues share their own interpretation of feedback."}, "next_node_id": "node_2c", "exploration_depth": "deep"}], "is_endpoint": false, "endpoint_type": null}, "node_2b": {"id": "node_2b", "persona_text": "Exactly. And I know I need to improve, but I also feel like I have strengths that maybe weren''t recognized. I''m not sure how to balance working on gaps while also using my strengths.", "persona_mood": "complex_balanced", "themes": ["Complexity", "Strengths", "Balance"], "choice_points": [{"id": "cp_node_2b_0", "option_text": "You''re recognizing areas for development, and you also feel you have strengths that weren''t acknowledged. You want to work on gaps while also using your strengths.", "preview_hint": "This captures the complexity", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["complex_reflection"], "competency_links": ["A6", "A4"], "feedback": {"immediate": "Excellent complex reflection! You''ve captured the tension between addressing gaps and leveraging strengths.", "learning_note": "Complex reflections honor both development needs and strengths."}, "next_node_id": "node_3a", "exploration_depth": "deep"}], "is_endpoint": false, "endpoint_type": null}, "node_2c": {"id": "node_2c", "persona_text": "Mainly around technical skills in some areas, and also around presenting to groups. But honestly, I feel pretty strong in other areas - like relationship building and problem-solving.", "persona_mood": "honest_balanced", "themes": ["Honesty", "Self-Awareness", "Strength-Based"], "choice_points": [{"id": "cp_node_2c_0", "option_text": "So you see development needs around technical skills and presenting, but you also recognize your strengths in relationship building and problem-solving.", "preview_hint": "This balances gaps with strengths", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["balanced_summary"], "competency_links": ["A6", "A4"], "feedback": {"immediate": "Excellent balanced summary! You''ve given equal weight to development needs and strengths.", "learning_note": "Balanced summaries maintain dignity while acknowledging development needs."}, "next_node_id": "node_3b", "exploration_depth": "deep"}, {"id": "cp_node_2c_1", "option_text": "Those are great strengths! How do you see those strengths supporting your development in the other areas?", "preview_hint": "This builds on strengths", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["strength_based_question"], "competency_links": ["A6", "C2"], "feedback": {"immediate": "Perfect strength-based question! This helps them see how their strengths support development.", "learning_note": "Strength-based questions help colleagues see resources for development."}, "next_node_id": "node_3c", "exploration_depth": "deep"}], "is_endpoint": false, "endpoint_type": null}, "node_3a": {"id": "node_3a", "persona_text": "That''s exactly it. I don''t want to lose focus on my strengths while I''m working on the gaps. I need both.", "persona_mood": "clarity_integrated", "themes": ["Clarity", "Integration", "Whole_Person"], "choice_points": [{"id": "cp_node_3a_0", "option_text": "So you want to develop in the gap areas while continuing to use and grow your strengths - you want a balanced approach.", "preview_hint": "This reflects integrated thinking", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["reflection_of_integration"], "competency_links": ["A6"], "feedback": {"immediate": "Perfect reflection! You''ve captured their integrated approach to development.", "learning_note": "Reflections that capture integration support holistic development."}, "next_node_id": "node_4a", "exploration_depth": "deep"}], "is_endpoint": false, "endpoint_type": null}, "node_3b": {"id": "node_3b", "persona_text": "Yeah. And honestly, hearing both sides acknowledged helps. I don''t feel as defensive when my strengths are recognized too.", "persona_mood": "validated_relieved", "themes": ["Validation", "Relief", "Less_Defensive"], "choice_points": [{"id": "cp_node_3b_0", "option_text": "So having both your development needs and your strengths acknowledged helps you feel less defensive and more open to learning.", "preview_hint": "This reflects the impact of balance", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["reflection_of_process"], "competency_links": ["A6", "A4"], "feedback": {"immediate": "Excellent reflection! You''ve captured how balanced acknowledgment reduces defensiveness.", "learning_note": "Balanced acknowledgment creates psychological safety for development."}, "next_node_id": "node_4b", "exploration_depth": "deep"}], "is_endpoint": false, "endpoint_type": null}, "node_3c": {"id": "node_3c", "persona_text": "I suppose my relationship building could help with presenting - I''m good at connecting with people. And my problem-solving could help me learn technical skills systematically.", "persona_mood": "insightful_creative", "themes": ["Insight", "Creativity", "Resourcefulness"], "choice_points": [{"id": "cp_node_3c_0", "option_text": "So you''re seeing how your relationship skills can support presenting, and your problem-solving can help with technical learning.", "preview_hint": "This reflects their resourcefulness", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["affirmation_reflection"], "competency_links": ["A6", "C2"], "feedback": {"immediate": "Excellent! You''ve affirmed their insight and reflected how their strengths support development.", "learning_note": "Affirming insights about strengths reinforces resourcefulness."}, "next_node_id": "node_end_excellent", "exploration_depth": "deep"}], "is_endpoint": false, "endpoint_type": null}, "node_2a": {"id": "node_2a", "persona_text": "I suppose. Thanks for confirming what I need to work on.", "persona_mood": "defensive_compliant", "themes": ["Defensiveness", "Compliance"], "choice_points": [], "is_endpoint": true, "endpoint_type": "transactional_only"}, "node_4a": {"id": "node_4a", "persona_text": "This conversation has really helped. I feel like I can work on the gaps without losing my strengths.", "persona_mood": "empowered_integrated", "themes": ["Empowerment", "Integration", "Hope"], "choice_points": [], "is_endpoint": true, "endpoint_type": "excellent_engagement"}, "node_4b": {"id": "node_4b", "persona_text": "Thanks. I feel much more open to working on my development now that I feel my strengths are also recognized.", "persona_mood": "motivated_safe", "themes": ["Motivation", "Safety", "Openness"], "choice_points": [], "is_endpoint": true, "endpoint_type": "excellent_engagement"}, "node_end_excellent": {"id": "node_end_excellent", "persona_text": "This has been really helpful. I can see a path forward that uses my strengths while addressing my development needs.", "persona_mood": "clear_confident", "themes": ["Clarity", "Confidence", "Path_Forward"], "choice_points": [], "is_endpoint": true, "endpoint_type": "excellent_engagement"}}}'::jsonb,
